SELECT MIN(Credit) AS Lowest_Invoice_Value
FROM master_txn_table
WHERE Product_Service = 'Repairing locomotives and railcars (except factory conversion, overhaul and rebuilding)' AND Transaction_DATE BETWEEN date('now', 'start of year') AND date('now') GROUP BY Product_Service;

SELECT MAX(transaction_date) AS last_fixed_income_sale
FROM master_txn_table
WHERE account = 'Fixed Income' AND transaction_type = 'sale';

SELECT MAX(transaction_date) AS last_sale_date
FROM master_txn_table
WHERE Product_Service = 'Window washing' AND Credit > 0 AND transaction_date = (SELECT MAX(transaction_date) FROM master_txn_table WHERE Product_Service = 'Window washing');

SELECT MAX(transaction_date) AS last_sale_date
FROM master_txn_table
WHERE Product_Service = 'Window washing' AND Credit > 0 AND transaction_date = (SELECT MAX(transaction_date) FROM master_txn_table WHERE Product_Service = 'Window washing');
